com.mirth.connect.plugins.javascriptstep.script:
if (msg['Parameters']['hosnum'].toString()) {
    tmp['QPD']['QPD.3'][0]['QPD.3.1'] = msg['Parameters']['hosnum'].toString();
} else if (msg['Parameters']['nhsnum'].toString()) {
    tmp['QPD']['QPD.3'][0]['QPD.3.1'] = msg['Parameters']['nhsnum'].toString();
    tmp['QPD']['QPD.3'][0]['QPD.3.2'] = "NHSNBR";
} else {
    tmp['QPD']['QPD.3'][0]['QPD.3.1'] = "";
}

properties.script:
var destination = responseMap.get('Send Q21');
var responseMessage = destination.getMessage();
var Xmsg = new XML(SerializerFactory.getSerializer('HL7V2').toXML(responseMessage));

//var xml_msg = '<?xml version="1.0" encoding="utf-8" ?>'+
//              '<XML><Patient Name="'+Xmsg['PID']['PID.5']['PID.5.1']+
//              '" Barcode="'+Xmsg['QRD']['QRD.8']['QRD.8.1']+'" /></XML>';

var sResp = ResponseFactory.getSentResponse(Xmsg)

responseMap.put('K21ResponseXML', sResp);

com.mirth.connect.plugins.javascriptrule.script:
// Check if the message id matches
var responseObj = responseMap.get('Send Q21');
if (responseObj) {
    var hl7Response = responseObj.getMessage();  // Get the HL7 message as a string
}

if (hl7Response) {
	var hl7Parser = new Packages.ca.uhn.hl7v2.parser.PipeParser();
	hl7Parser.getParserConfiguration().setValidating(false);
	var hl7Msg = hl7Parser.parse(hl7Response);  // Parse HL7 without strict validation

	var mshSegment = hl7Msg.get("MSH");  
	var messageControlID = String(mshSegment.getField(10, 0));  // Extract MSH.10.1

	if (messageControlID.split("-")[0] != connectorMessage.getMessageId()) {
		logger.error("Message ID sent does not match the one being received!");
		destinationSet.remove(["Create response"]);
		return false;
	}
}

return true;

channel.postprocessingScript:
// This script executes once after a message has been processed
